-- Seed: Division Politico-Territorial de Venezuela
-- 24 estados, 335 municipios

-- Clear existing data (order matters for FK)
truncate table public.parroquia cascade;
truncate table public.municipio cascade;
truncate table public.estado cascade;

-- Reset sequences
alter sequence public.estado_id_seq restart with 1;
alter sequence public.municipio_id_seq restart with 1;
alter sequence public.parroquia_id_seq restart with 1;

-- Insert estados

-- Insert municipios

-- Insert parroquias

-- Indexes
create index if not exists idx_municipio_estado on public.municipio(estado_id, nombre);
create index if not exists idx_parroquia_municipio on public.parroquia(municipio_id, nombre);

-- Helper: full geo chain for an institution
create or replace function public.get_institucion_geo(p_institucion_id bigint)
returns table (
  institucion_nombre text,
  direccion text,
  parroquia text,
  municipio text,
  estado text
) language plpgsql stable as $$
begin
  return query
    select i.nombre, i.direccion, p.nombre, m.nombre, e.nombre
    from public.institucion i
    join public.parroquia p on p.id = i.parroquia_id
    join public.municipio m on m.id = p.municipio_id
    join public.estado e on e.id = m.estado_id
    where i.id = p_institucion_id;
end;
$$;
